                        />
                      </Link>
                      <div className="flex-1 min-w-0">
                        <Link href={`/instrutor/${inst.slug}`}>
                          <h3 className="font-bold text-sm md:text-lg group-hover:text-[#EAB308] transition-colors truncate">
                            {inst.nome}
