import { uploadFoto, uploadDocumento } from '@/lib/storage'
import { telefoneMask, cepMask } from '@/lib/validations'
import { toast } from 'sonner'
import { useViaCep } from '@/hooks/useViaCep'
import type { PlanoTipo } from '@/types'
import {
  User,
  FileText,
  MapPin,
  Car,
  Star,
  Clock,
  CheckCircle,
  XCircle,
  AlertCircle,
  Shield,
  Crown,
  Eye,
  TrendingUp,
  MessageSquare,
  MessageCircle,
  LogOut,
  Check,
  Pencil,
  Save,
  X,
  Headphones,
  Plus,
